-- Query: 000AuditReport
SELECT [000AuditSessionSelectByID].CustomerID, Customers.LastName, Customers.FirstName, Customers.Gender, Customers.Address, Customers.City, Customers.State, Customers.ZipCode, Customers.Phone, Customers.StudentID, Customers.SchoolID, Customers.WebPassword, [000AuditOrdersAmount].OrderID, [000AuditOrdersAmount].OrderNumber, [000AuditOrdersAmount].OrderDate, IIf(IsNull([OrderTotal]),0,[OrderTotal]) AS OrderBalDue, IIf(IsNull([000AuditOrdersAmount].[TotalOrder]),0,[000AuditOrdersAmount].[TotalOrder]) AS TotalOrder, [000AuditOrdersAmount].SalesTax, IIf(IsNull([000AuditOrdersTotalPayments].[TotalOrderPayments]),0,[000AuditOrdersTotalPayments].[TotalOrderPayments]) AS TotalOrderPayments, Schools.School, [000AuditOrdersPayments].Date AS DatePaid, IIf(IsNull([Method]),'',IIf([Method]=1,'Check',IIf([Method]=2,'Credit Card','Cash'))) AS PaymentMethod, [000AuditOrdersPayments].Amount, [Users].[FirstName] & ' ' & [Users].[LastName] AS SalesPerson
FROM ((000AuditSessionSelectByID LEFT JOIN (Schools RIGHT JOIN Customers ON Schools.SchoolID = Customers.SchoolID) ON [000AuditSessionSelectByID].CustomerID = Customers.CustomerID) LEFT JOIN ((000AuditOrdersAmount LEFT JOIN 000AuditOrdersTotalPayments ON ([000AuditOrdersAmount].CustomerID = [000AuditOrdersTotalPayments].CustomerID) AND ([000AuditOrdersAmount].OrderID = [000AuditOrdersTotalPayments].OrderID)) LEFT JOIN 000AuditOrdersPayments ON ([000AuditOrdersTotalPayments].CustomerID = [000AuditOrdersPayments].CustomerID) AND ([000AuditOrdersTotalPayments].OrderID = [000AuditOrdersPayments].OrderID)) ON Customers.CustomerID = [000AuditOrdersAmount].CustomerID) LEFT JOIN Users ON [000AuditOrdersAmount].UserID = Users.UserID;

